/**
 * n8n Code Node Script: Shopee Deep Link Generator
 */
async function resolveShortLink(url) {
    if (!url) return '';
    if (url.includes('shope.ee') || url.includes('shp.ee') || url.includes('shorturl')) {
        try {
            const response = await fetch(url, {
                method: 'GET',
                headers: {
                    'User-Agent': 'Mozilla/5.0 (Windows)'
                },
                redirect: 'follow'
            });
            return response.url;
        } catch (error) {
            return url;
        }
    }
    return url;
}

function generateShopeeDeepLink(url) {
    if (!url) return '';
    try {
        let shopId = '';
        let productId = '';
        const regexPattern1 = /-i\.(\d+)\.(\d+)/;
        const match1 = url.match(regexPattern1);
        if (match1) {
            shopId = match1[1];
            productId = match1[2];
        } else {
            const regexPattern2 = /\/product\/(\d+)\/(\d+)/;
            const match2 = url.match(regexPattern2);
            if (match2) {
                shopId = match2[1];
                productId = match2[2];
            }
        }
        if (shopId && productId) {
            return `shopeevn://product/${shopId}/${productId}`;
        }
        if (url.includes('shopee.vn')) {
            return `shopeevn://`;
        }
        return url;
    } catch (e) {
        return url;
    }
}

const items = $input.all();
const results = [];
for (const item of items) {
    const data = { ...item.json };
    if (data.Status === 'PENDING' && data.Original_Link) {
        const resolvedUrl = await resolveShortLink(data.Original_Link);
        data.Deep_Link = generateShopeeDeepLink(resolvedUrl);
    }
    results.push({ json: data });
}
return results;

/**
 * n8n Code Node Script: Image Path & Compression URL Generator
 */
const items = $input.all();
const results = [];
for (const item of items) {
    const data = { ...item.json };
    if (data.Status === 'PENDING' && data.Image_URL) {
        if (data.Image_URL.startsWith('images/product_') && data.Image_URL.endsWith('.webp')) {
            results.push({ json: data });
            continue;
        }
        const rawImageUrl = data.Image_URL.trim();
        const productId = data.ID || Math.floor(Math.random() * 1000000);
        const localFileName = `images/product_${productId}.webp`;
        const compressUrl = `https://images.weserv.nl/?url=${encodeURIComponent(rawImageUrl)}&output=webp&q=75&w=400`;
        data.Temp_Compress_URL = compressUrl;
        data.Temp_Local_Path = localFileName;
        data.Image_URL = localFileName;
    }
    results.push({ json: data });
}
return results;

/**
 * n8n Code Node Script: Cache Builder (data.json Generator)
 */
const DEFAULT_KOL_CONFIG = {
    avatar: "https://api.dicebear.com/7.x/adventurer/svg?seed=Lisa",
    name: "@khanhvy.official",
    bio: "✨ Welcome to my shop! Góc chia sẻ các sản phẩm chính hãng mình đã trực tiếp trải nghiệm và review trên TikTok. Săn deal hời mỗi ngày cùng mình nhé! 👇",
    shopee_mall: "https://shopee.vn/m/shopeemall"
};

const items = $input.all();
const products = [];
let kolConfig = { ...DEFAULT_KOL_CONFIG };

for (const item of items) {
    const data = item.json;
    if (data.Category === 'CONFIG' || data.ID === -1 || data.Title === 'KOL_CONFIG') {
        kolConfig.name = data.Original_Link || kolConfig.name;
        kolConfig.bio = data.Deep_Link || kolConfig.bio;
        kolConfig.avatar = data.Image_URL || kolConfig.avatar;
        kolConfig.shopee_mall = data.Original_Link || kolConfig.shopee_mall;
        continue;
    }
    if (data.Status === 'DONE') {
        products.push({
            ID: Number(data.ID) || Math.floor(Math.random() * 1000000),
            Category: data.Category ? data.Category.trim() : 'Sản phẩm khác',
            Title: data.Title ? data.Title.trim() : 'Sản phẩm Shopee',
            Original_Link: data.Original_Link ? data.Original_Link.trim() : '',
            Deep_Link: data.Deep_Link ? data.Deep_Link.trim() : '',
            Image_URL: data.Image_URL ? data.Image_URL.trim() : '',
            Status: 'DONE'
        });
    }
}
products.sort((a, b) => b.ID - a.ID);
const finalData = {
    config: kolConfig,
    products: products
};

return [{
    json: {
        file_name: "data.json",
        file_content: JSON.stringify(finalData, null, 2),
        total_products: products.length,
        generated_at: new Date().toISOString()
    }
}];
